function applySvgState(markup, selectedSlug, hoveredSlug) {
  return markup.replace(/<g([^>]*\bdata-muscle="([^"]+)"[^>]*)>/g, (match, attrs, slug) => {
    if (!/\bmuscle-zone\b/.test(attrs)) return match;

    const currentClassMatch = attrs.match(/\bclass="([^"]*)"/);
    if (!currentClassMatch) return match;

    let className = currentClassMatch[1]
      .replace(/\bactive\b/g, "")
      .replace(/\bis-hovered\b/g, "")
      .replace(/\s+/g, " ")
      .trim();

    if (slug === selectedSlug) {
      className = `${className} active`.trim();
    } else if (slug === hoveredSlug) {
      className = `${className} is-hovered`.trim();
    }

    return `<g${attrs.replace(currentClassMatch[0], `class="${className}"`)}>`;
  });
}

export default function MuscleMapSvg({ selectedSlug, hoveredSlug, setHoveredSlug, onSelect }) {
  const renderedSvg = useMemo(
    () => applySvgState(SVG_MARKUP, selectedSlug, hoveredSlug),
    [selectedSlug, hoveredSlug]
  );

  return (
    <div
      className="nashfit-real-muscle-map overflow-hidden rounded-[1.4rem] border border-[color:var(--stroke)] bg-[#9ea3b0] p-2.5 shadow-inner"
      onMouseOver={(event) => {
        const slug = event.target?.closest?.("[data-muscle]")?.dataset?.muscle;
        if (slug) setHoveredSlug(slug);
      }}
      onMouseLeave={() => setHoveredSlug(null)}
      onFocus={(event) => {
        const slug = event.target?.closest?.("[data-muscle]")?.dataset?.muscle;
        if (slug) setHoveredSlug(slug);
      }}
      onBlur={() => setHoveredSlug(null)}
      onClick={(event) => {
        const slug = event.target?.closest?.("[data-muscle]")?.dataset?.muscle;
        if (slug) onSelect(slug);
      }}
      onKeyDown={(event) => {
        if (event.key !== "Enter" && event.key !== " ") return;
        const slug = event.target?.closest?.("[data-muscle]")?.dataset?.muscle;
        if (!slug) return;
        event.preventDefault();
        onSelect(slug);
      }}
      dangerouslySetInnerHTML={{ __html: renderedSvg }}
    />
  );
}
